use alloy_primitives::{Address, Bytes, B256};
use jsonrpsee::{core::RpcResult, proc_macros::rpc};
use serde::{Deserialize, Serialize};

/// Request parameters for submitting async execution results
#[derive(Debug, Clone, Serialize, Deserialize)]

    pub enabled: bool,
}

/// Single scheduled-transaction incident captured during payload building.
///
/// Scope: any `BlockExecutionError` returned from `execute_transaction` on a
/// scheduled (EIP-2718 type 0x10) TX. The gas-extraction "no recognized
/// Scheduler terminal event" case was moved to an in-crate 0-gas contribution
/// + structured log in `ritual-alloy-evm-internal#54`, so that specific
/// marker no longer appears here; what does surface is `InvalidTx`, pool,
/// and DB errors on the scheduled execution path.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ScheduledIncidentDebug {
    /// Monotonic local sequence number.
    pub sequence: u64,
    /// Timestamp in microseconds since UNIX epoch.
    #[serde(rename = "tsMicros")]
    pub ts_micros: u128,
    /// Payload id associated with the build attempt, when available.
    #[serde(rename = "payloadId")]
    pub payload_id: Option<String>,
